class Solution:
    def new21Game(self, n: int, k: int, maxPts: int) -> float:
        dp = [0.0] * (n + 1)
        dp[0] = 1.0
        for i in range(1, n + 1):
            for j in range(1, min(i, maxPts) + 1):
                if i - j >= k:
                    dp[i] += dp[i - j] / maxPts
        return sum(dp[:n + 1])
```
